+export function drawCharacter(
+  ctx: CanvasRenderingContext2D,
+  type: CharacterType,
+  state: AnimState,
+  x: number, y: number, s: number, frame: number,
+  agentId?: string,
+  currentJob?: string | null,
+) {
+  const id = agentId ?? `${type}-${Math.round(x)}`;
+  const palette = PALETTE_MAP[type];
+  const cs = getCS(id, x, y);
+  const flipH = cs.dir === 'left';
+
+  // Advance walk frame if moving
+  if (cs.moving) {
+    if (frame % WALK_FRAME_DURATION === 0) {
+      cs.wf = (cs.wf + 1) % WALK_FRAMES_MAP[type].length;
+    }
+  } else {
+    cs.wf = 0;
+  }
+
+  // Determine sprite frame based on state and movement
+  let spriteFrame: string[];
+  if (cs.moving) {
+    spriteFrame = WALK_FRAMES_MAP[type][cs.wf];
+  } else {
+    // Idle frames cycle slower
+    const idleFrames = IDLE_FRAMES_MAP[type];
+    const idleFrameIndex = Math.floor(frame / IDLE_FRAME_DURATION) % idleFrames.length;
+    spriteFrame = idleFrames[idleFrameIndex];
+  }
+
+  // Bobbing effect for idle and working states
+  const bob = state === 'idle' ? Math.sin(frame * 0.05) * 1.2 : state === 'working' ? Math.sin(frame * 0.1) * 0.8 : 0;
+  const drawY = cs.y + bob;
+
+  // Drop shadow
+  ctx.fillStyle = 'rgba(0,0,0,0.3)';
+  ctx.beginPath();
+  ctx.ellipse(cs.x + 8 * s, drawY + spriteFrame.length * s + 2, 7 * s, 2 * s, 0, 0, Math.PI * 2);
+  ctx.fill();
+
+  drawSpriteDef(ctx, spriteFrame, palette, cs.x, drawY, s, flipH);
+
+  drawStatusEffect(ctx, state, cs.x, drawY, s, frame);
+  if (agentId) {
+    updateBubble(id, state, currentJob ?? null, frame);
+    drawBubble(ctx, id, cs.x + 8 * s, drawY - 4);
+  }
+}
